package com.edubridge.homeassigment;

public class CharacterPatternUsingLoops {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int i =1;
		int j =1;
		int a =1;
		
		for(i=1;i<=5;i++)
		{
			for(j=1;j<i+1;j++)
			{
				//prints the value of number
				System.out.print("* ");
				
			}
			
			System.out.println();
		}

	}

}
